CREATE TABLE IF NOT EXISTS debt_metrics (
    id INT PRIMARY KEY AUTO_INCREMENT,
    institution_id INT NOT NULL,
    cohort_year_id INT NOT NULL,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (institution_id) REFERENCES institution(id) ON DELETE CASCADE,
    FOREIGN KEY (cohort_year_id) REFERENCES cohort_year(id),
    UNIQUE KEY unique_institution_cohort (institution_id, cohort_year_id),
    INDEX idx_institution_id (institution_id),
    INDEX idx_cohort_year_id (cohort_year_id),
    -- Legacy Fields for debt_metrics,
    median_federal_loan_debt DECIMAL(10, 2),
    median_federal_loan_debt_10yr_payment INT,
    median_parent_plus_debt DECIMAL(10, 2),
    parent_plus_debt_10yr_payment INT,
    pct_parent_plus_low DECIMAL(5, 2),
    pct_parent_plus_high DECIMAL(5, 2)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

